}
```

> **Note:** `fs-extra` version should be verified against other packages in the monorepo (search `packages/*/package.json` for `"fs-extra"`) and pinned to the same version. `@types/fs-extra` similarly.

---

### 2. `packages/generator-rest-client/tsconfig.json`

```json
{
  "extends": "../../tsconfig.json",
  "include": ["./**/*"]
}
```

---

### 3. `packages/generator-rest-client/tsconfig.build.json`

```json
{
  "extends": "../../tsconfig.build.regular.json",
  "compilerOptions": {
    "outDir": "dist",
    "rootDir": "src"
  },
  "include": ["src"]
}
```

---

### 4. `packages/generator-rest-client/helpers/build.ts`

Uses `createAdapterConfig` (not the pre-made `adapterConfig` constant) so we can splice in a `banner` with the Node shebang on the CJS output, making the built file directly executable as the generator binary.

```typescript
import { build } from '../../../helpers/compile/build'
import { createAdapterConfig } from '../../../helpers/compile/configs'

const entries = createAdapterConfig([{ entry: 'src/index.ts', outfile: 'dist/index' }])

// The CJS bundle is used as the generator binary; it needs a shebang so that
// the OS can execute it directly when Prisma CLI spawns the generator process.
const config = entries.map((c) => (c.format === 'cjs' ? { ...c, banner: { js: '#!/usr/bin/env node' } } : c))

void build(config)
```

---

### 5. `packages/generator-rest-client/src/template.ts`

String-template helpers. Two responsibilities:
1. **Type mapping** — converts DMMF scalar/enum/object `Field.type` + `Field.kind` to a TypeScript type string.
2. **Code generation** — produces the TypeScript source text for interfaces and the `RestClient` method objects.

#### Scalar type map

| Prisma type | TypeScript type |
|-------------|-----------------|
| `String`    | `string`        |
| `Int`       | `number`        |
| `Float`     | `number`        |
| `Boolean`   | `boolean`       |
| `DateTime`  | `Date`          |
| `BigInt`    | `bigint`        |
| `Decimal`   | `string`        |
| `Bytes`     | `Uint8Array`    |
| `Json`      | `unknown`       |
| anything else (enum name / relation model) | use the name as-is |

#### Functions to implement

```typescript
// Map a DMMF Field to its TypeScript type annotation string.
// - scalar kinds use the table above
// - object kinds (relations) use the related model name
// - enum kinds use the enum name
// - unsupported kind uses `unknown`
// Wraps in Array<...> when isList; adds `| null` when !isRequired.
export function fieldTypeToTs(field: DMMF.Field): string

// Generate the main model read interface, including all fields.
export function generateModelInterface(model: DMMF.Model): string

// Generate CreateInput interface: all non-generated, non-relation scalar/enum
// fields; required fields stay required, optional (isRequired=false) become
// optional `?:` properties.
export function generateCreateInput(model: DMMF.Model): string

// Generate UpdateInput interface: same as CreateInput but all properties are
// optional (`?:`), excluding id/auto-generated fields.
export function generateUpdateInput(model: DMMF.Model): string

// Generate WhereUniqueInput interface: id fields plus any @unique scalar fields,
// all optional (`?:`) — caller passes at least one.
export function generateWhereUniqueInput(model: DMMF.Model): string

// Generate the per-model property on RestClient (the object with the 5 CRUD
// methods). Takes the model name (for URL slug in kebab-case) and the
// interface/input names as parameters.
export function generateModelMethods(model: DMMF.Model): string

// File-level header comment.
export const FILE_HEADER: string
```

---

### 6. `packages/generator-rest-client/src/generator.ts`

Main generation logic. Orchestrates template helpers and writes the output file.

```typescript
import fs from 'node:fs/promises'
import path from 'node:path'
import type { GeneratorOptions } from '@prisma/generator'
import { parseEnvValue } from '@prisma/internals'
import { ensureDir } from 'fs-extra'
import {
  FILE_HEADER,
  generateModelInterface,
  generateCreateInput,
  generateUpdateInput,
  generateWhereUniqueInput,
  generateModelMethods,
} from './template'

/** Generates and writes `rest-client.ts` into the resolved output directory. */
export async function generate(options: GeneratorOptions): Promise<void> {
  const outputDir = parseEnvValue(options.generator.output!)
  const models = options.dmmf.datamodel.models

  // Build source text section by section
  const sections: string[] = [FILE_HEADER]

  // 1. Model interfaces + input types
  for (const model of models) {
    sections.push(generateModelInterface(model))
    sections.push(generateCreateInput(model))
    sections.push(generateUpdateInput(model))
    sections.push(generateWhereUniqueInput(model))
  }

  // 2. RestClient class
  const methodBlocks = models.map(generateModelMethods).join('\n\n')
  sections.push(
    [
      'export class RestClient {',
      '  constructor(private readonly baseUrl: string) {}',
      '',
      methodBlocks,
      '}',
    ].join('\n'),
  )

  const source = sections.join('\n\n')

  await ensureDir(outputDir)
  await fs.writeFile(path.join(outputDir, 'rest-client.ts'), source, 'utf-8')
}
```

---

### 7. `packages/generator-rest-client/src/index.ts`

Generator entry point. Calls `generatorHandler` with `onManifest` and `onGenerate` callbacks.

```typescript
import type { GeneratorConfig, GeneratorManifest } from '@prisma/generator'
import { generatorHandler } from '@prisma/generator-helper'
import { generate } from './generator'

generatorHandler({
  onManifest(_config: GeneratorConfig): GeneratorManifest {
    return {
      prettyName: 'Prisma REST Client Generator',
      defaultOutput: './generated/rest-client',
    }
  },

  async onGenerate(options) {
    await generate(options)
  },
})
```

---

## File to modify

### `tsconfig.build.bundle.json`

Add one line to the `compilerOptions.paths` object (after the existing `@prisma/generator-helper` entry, maintaining alphabetical order among `@prisma/generator*` entries):

```json
"@prisma/generator-rest-client": ["./packages/generator-rest-client/src"],
```

---

## Generated output shape

For a schema with a `User` model (`id Int @id`, `email String @unique`, `name String?`), the emitted `rest-client.ts` will contain:

```typescript
// Auto-generated by @prisma/generator-rest-client. Do not edit manually.

export interface User {
  id: number
  email: string
  name: string | null
}

export interface UserCreateInput {
  email: string
  name?: string | null
}

