      const params = new URLSearchParams(where as Record<string, string>)
      const res = await fetch(`${this.baseUrl}/user?${params}`, {
        method: 'PATCH',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(data),
      })
      return res.json() as Promise<User>
    },
    delete: async (where: UserWhereUniqueInput): Promise<User> => {
