// Map a DMMF Field to its TypeScript type annotation string.
// - scalar kinds use the table above
// - object kinds (relations) use the related model name
// - enum kinds use the enum name
// - unsupported kind uses `unknown`
// Wraps in Array<...> when isList; adds `| null` when !isRequired.
export function fieldTypeToTs(field: DMMF.Field): string

// Generate the main model read interface, including all fields.
export function generateModelInterface(model: DMMF.Model): string

// Generate CreateInput interface: all non-generated, non-relation scalar/enum
// fields; required fields stay required, optional (isRequired=false) become
// optional `?:` properties.
export function generateCreateInput(model: DMMF.Model): string

// Generate UpdateInput interface: same as CreateInput but all properties are
// optional (`?:`), excluding id/auto-generated fields.
export function generateUpdateInput(model: DMMF.Model): string

// Generate WhereUniqueInput interface: id fields plus any @unique scalar fields,
// all optional (`?:`) — caller passes at least one.
export function generateWhereUniqueInput(model: DMMF.Model): string

// Generate the per-model property on RestClient (the object with the 5 CRUD
// methods). Takes the model name (for URL slug in kebab-case) and the
// interface/input names as parameters.
export function generateModelMethods(model: DMMF.Model): string

// File-level header comment.
export const FILE_HEADER: string
```

---

### 6. `packages/generator-rest-client/src/generator.ts`

Main generation logic. Orchestrates template helpers and writes the output file.

```typescript
import fs from 'node:fs/promises'
import path from 'node:path'
import type { GeneratorOptions } from '@prisma/generator'
import { parseEnvValue } from '@prisma/internals'
import { ensureDir } from 'fs-extra'
import {
  FILE_HEADER,
  generateModelInterface,
  generateCreateInput,
  generateUpdateInput,
  generateWhereUniqueInput,
  generateModelMethods,
} from './template'

/** Generates and writes `rest-client.ts` into the resolved output directory. */
export async function generate(options: GeneratorOptions): Promise<void> {
  const outputDir = parseEnvValue(options.generator.output!)
  const models = options.dmmf.datamodel.models

  // Build source text section by section
  const sections: string[] = [FILE_HEADER]

  // 1. Model interfaces + input types
  for (const model of models) {
    sections.push(generateModelInterface(model))
    sections.push(generateCreateInput(model))
    sections.push(generateUpdateInput(model))
    sections.push(generateWhereUniqueInput(model))
  }

  // 2. RestClient class
  const methodBlocks = models.map(generateModelMethods).join('\n\n')
  sections.push(
    [
      'export class RestClient {',
      '  constructor(private readonly baseUrl: string) {}',
      '',
      methodBlocks,
      '}',
    ].join('\n'),
  )

  const source = sections.join('\n\n')

  await ensureDir(outputDir)
  await fs.writeFile(path.join(outputDir, 'rest-client.ts'), source, 'utf-8')
}
```

---

### 7. `packages/generator-rest-client/src/index.ts`

Generator entry point. Calls `generatorHandler` with `onManifest` and `onGenerate` callbacks.

