import type { DMMF } from '@prisma/dmmf'

export const FILE_HEADER = `\
// Auto-generated by @prisma/generator-rest-client. Do not edit manually.`

/** Maps a Prisma scalar type name to its TypeScript equivalent. */
function scalarToTs(prismaType: string): string {
  switch (prismaType) {
    case 'String':
      return 'string'
    case 'Int':
    case 'Float':
      return 'number'
    case 'Boolean':
      return 'boolean'
    case 'DateTime':
      return 'Date'
    case 'BigInt':
      return 'bigint'
    case 'Decimal':
      // Use string to preserve arbitrary precision.
      return 'string'
    case 'Bytes':
      return 'Uint8Array'
    case 'Json':
      return 'unknown'
    default:
      // Enum names and composite type names pass through as-is.
      return prismaType
  }
}

/**
 * Returns the TypeScript type annotation string for a DMMF field, accounting
 * for list and nullability wrappers.
 */
export function fieldTypeToTs(field: DMMF.Field): string {
  let base: string

  switch (field.kind) {
    case 'scalar':
      base = scalarToTs(field.type)
      break
    case 'enum':
      base = field.type
      break
    case 'object':
      // Relations reference the related model type by name.
      base = field.type
      break
    case 'unsupported':
      base = 'unknown'
      break
  }

  if (field.isList) {
    base = `${base}[]`
  }

  if (!field.isRequired) {
    base = `${base} | null`
  }

  return base
}

/** Generates the main read interface for a model, including all fields. */
export function generateModelInterface(model: DMMF.Model): string {
  const fields = model.fields
    .map((field) => {
      const doc = field.documentation ? `  /** ${field.documentation} */\n` : ''
      return `${doc}  ${field.name}: ${fieldTypeToTs(field)}`
    })
    .join('\n')

  return `export interface ${model.name} {\n${fields}\n}`
}

/**
