      const optional = !field.isRequired || isAutoGenerated
      const separator = optional ? '?:' : ':'
      const typeStr = field.isList ? `${scalarToTs(field.type)}[]` : scalarToTs(field.type)
      const nullable = !field.isRequired ? ` | null` : ''
      return `  ${field.name}${separator} ${typeStr}${nullable}`
